async function transform(input, context) {
  const originalName = input.files?.[0]?.originalName || 'video';
  const fileSize = input.files?.[0]?.size || 0;

  // Formater la taille
  const formatSize = (bytes) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  return {
    id: context.executionId,
    processedAt: new Date().toISOString(),
    source: {
      filename: originalName,
      size: formatSize(fileSize),
      sizeBytes: fileSize
    },
    outputs: {
      thumbnail: {
        path: `executions/${context.executionId}/thumbnail.jpg`,
        description: 'Image extraite à 2 secondes'
      },
      preview: {
        path: `executions/${context.executionId}/preview.gif`,
        description: 'GIF animé de 3 secondes (10 fps)'
      }
    },
    status: 'success'
  };
}
